const body = $input.first().json.body;
const messages = body.messages || [];
const lastMessage = messages[messages.length - 1]?.content || '';
const sessionId = body.sessionId || 'default';
return [{ json: { chatInput: lastMessage, sessionId } }];

const name = $fromAI('name', 'Chat Visitor', { description: 'The visitor name, or Chat Visitor if unknown' });
const email = $fromAI('email', '', { description: 'The visitor email address (required)' });
const serviceInterest = $fromAI('service_interest', 'General Inquiry', { description: 'What service they are interested in' });

if (!email) {
  return 'Error: email is required to save a lead.';
}

try {
  const response = await $helpers.httpRequest({
